@startuml
skinparam classAttributeIconSize 0
skinparam shadowing false
skinparam roundcorner 10
skinparam class {
  BackgroundColor #F7F7F7
  BorderColor #333333
  HeaderBackgroundColor #F7F7F7
}

abstract class "Listenable" as Listenable <<abstract>> {
  --
  void addListener(VoidCallback listener)
  void removeListener(VoidCallback listener)
}

abstract class "ValueListenable<T>" as ValueListenableT <<abstract>> {
  T get value
}

class "ChangeNotifier" as ChangeNotifier {
  ObserverList<VoidCallback> _listeners
  bool get hasListeners
  --
  void dispose()
  void notifyListeners()
}

class "ValueNotifier<T>" as ValueNotifierT {
  T get value
  --
  set value(T newValue)
}

ValueListenableT -|> Listenable
ChangeNotifier ..|> Listenable

ValueNotifierT -|> ChangeNotifier
ValueNotifierT ..|> ValueListenableT

@enduml
